"use strict";const input=document.querySelector(".input"),button=document.querySelector(".button"),total=document.querySelector(".total");function init(t){let e=t.split("-"),n="";for(let t=e[0];t<=e[1];t++)n+=t+";";let u=n.substring(0,n.length-1);return total.textContent=u}button.addEventListener("click",()=>{init(input.value)});